// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title BookEscrow
 * @notice Trust-minimized escrow for "A Multiverse of Love" by Interstellar Psychology.
 *
 * Flow:
 *   1. Buyer approves this contract on the token, then calls createOrder().
 *      Funds split into cost (covers print+ship) and profit (refundable portion).
 *   2. Author calls fulfillOrder() with a shipping-proof hash → cost released immediately.
 *   3. Buyer has DISPUTE_WINDOW days after fulfillment to call claimProfitRefund().
 *      If they do nothing, anyone can call releaseProfit() after the window to pay the author.
 *   4. If the author never fulfills within FULFILLMENT_DEADLINE, buyer can emergencyRefund()
 *      to recover the full amount.
 */
interface IERC20 {
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function transfer(address to, uint256 amount) external returns (bool);
}

contract BookEscrow {
    /* ─── Constants ─────────────────────────────────────────────────── */
    uint64 public constant DISPUTE_WINDOW      = 21 days;
    uint64 public constant FULFILLMENT_DEADLINE = 30 days;

    /* ─── State ──────────────────────────────────────────────────────── */
    address public immutable author;

    enum Status { Paid, Fulfilled, Released, Refunded }

    struct Order {
        address buyer;
        address token;
        uint256 cost;           // released to author on fulfillOrder
        uint256 profit;         // refundable to buyer within window
        uint64  createdAt;
        uint64  fulfilledAt;    // 0 until fulfilled
        bytes32 shippingHash;   // keccak256 of shipping proof
        Status  status;
    }

    mapping(bytes32 => Order) public orders;

    /* ─── Events ─────────────────────────────────────────────────────── */
    event OrderCreated   (bytes32 indexed id, address indexed buyer, address token, uint256 cost, uint256 profit);
    event OrderFulfilled (bytes32 indexed id, bytes32 shippingHash, uint64 fulfilledAt);
    event ProfitRefunded (bytes32 indexed id, address indexed buyer, uint256 amount);
    event ProfitReleased (bytes32 indexed id, address indexed author, uint256 amount);
    event EmergencyRefund(bytes32 indexed id, address indexed buyer, uint256 amount);

    /* ─── Errors ─────────────────────────────────────────────────────── */
    error OrderExists();
    error OrderNotFound();
    error NotBuyer();
    error NotAuthor();
    error WrongStatus(Status current, Status required);
    error WindowOpen();
    error WindowClosed();
    error DeadlineNotReached();
    error TransferFailed();
    error ZeroAmount();

    constructor(address _author) {
        require(_author != address(0), "Zero author");
        author = _author;
    }

    /* ─── Buyer: create order ─────────────────────────────────────────── */

    /**
     * @notice Lock tokens into escrow. Call token.approve(escrowAddr, cost+profit) first.
     * @param id       Unique order ID (keccak256 of bookId+buyer, or any random bytes32).
     * @param token    BEP-20 token address (DOGE or PEPE on BSC).
     * @param cost     Amount that covers production + shipping (released on fulfillment).
     * @param profit   Amount that stays locked for the dispute window.
     */
    function createOrder(
        bytes32 id,
        address token,
        uint256 cost,
        uint256 profit
    ) external {
        if (orders[id].buyer != address(0)) revert OrderExists();
        if (cost == 0 && profit == 0) revert ZeroAmount();

        uint256 total = cost + profit;
        bool ok = IERC20(token).transferFrom(msg.sender, address(this), total);
        if (!ok) revert TransferFailed();

        orders[id] = Order({
            buyer:        msg.sender,
            token:        token,
            cost:         cost,
            profit:       profit,
            createdAt:    uint64(block.timestamp),
            fulfilledAt:  0,
            shippingHash: bytes32(0),
            status:       Status.Paid
        });

        emit OrderCreated(id, msg.sender, token, cost, profit);
    }

    /* ─── Author: fulfill ─────────────────────────────────────────────── */

    /**
     * @notice Record shipping and release the cost portion to the author immediately.
     * @param id           Order ID.
     * @param shippingHash keccak256 of the tracking number / shipping receipt.
     */
    function fulfillOrder(bytes32 id, bytes32 shippingHash) external {
        if (msg.sender != author) revert NotAuthor();
        Order storage o = orders[id];
        if (o.buyer == address(0)) revert OrderNotFound();
        if (o.status != Status.Paid) revert WrongStatus(o.status, Status.Paid);

        o.status       = Status.Fulfilled;
        o.fulfilledAt  = uint64(block.timestamp);
        o.shippingHash = shippingHash;

        // Release cost to author immediately
        if (o.cost > 0) {
            bool ok = IERC20(o.token).transfer(author, o.cost);
            if (!ok) revert TransferFailed();
        }

        emit OrderFulfilled(id, shippingHash, o.fulfilledAt);
    }

    /* ─── Buyer: claim profit refund during window ─────────────────────── */

    /**
     * @notice Buyer calls this within DISPUTE_WINDOW days of fulfillment to get profit back.
     *         No approval from the author required — the contract just executes.
     */
    function claimProfitRefund(bytes32 id) external {
        Order storage o = orders[id];
        if (o.buyer == address(0)) revert OrderNotFound();
        if (msg.sender != o.buyer) revert NotBuyer();
        if (o.status != Status.Fulfilled) revert WrongStatus(o.status, Status.Fulfilled);
        if (block.timestamp > o.fulfilledAt + DISPUTE_WINDOW) revert WindowClosed();

        o.status = Status.Refunded;
        uint256 amount = o.profit;

        if (amount > 0) {
            bool ok = IERC20(o.token).transfer(o.buyer, amount);
            if (!ok) revert TransferFailed();
        }

        emit ProfitRefunded(id, o.buyer, amount);
    }

    /* ─── Anyone: release profit after window ──────────────────────────── */

    /**
     * @notice After DISPUTE_WINDOW has elapsed without a refund claim, anyone can release
     *         the escrowed profit to the author.
     */
    function releaseProfit(bytes32 id) external {
        Order storage o = orders[id];
        if (o.buyer == address(0)) revert OrderNotFound();
        if (o.status != Status.Fulfilled) revert WrongStatus(o.status, Status.Fulfilled);
        if (block.timestamp <= o.fulfilledAt + DISPUTE_WINDOW) revert WindowOpen();

        o.status = Status.Released;
        uint256 amount = o.profit;

        if (amount > 0) {
            bool ok = IERC20(o.token).transfer(author, amount);
            if (!ok) revert TransferFailed();
        }

        emit ProfitReleased(id, author, amount);
    }

    /* ─── Buyer: emergency refund if author never fulfills ─────────────── */

    /**
     * @notice If the author hasn't fulfilled within FULFILLMENT_DEADLINE, buyer can
     *         withdraw the full amount (cost + profit) themselves.
     */
    function emergencyRefund(bytes32 id) external {
        Order storage o = orders[id];
        if (o.buyer == address(0)) revert OrderNotFound();
        if (msg.sender != o.buyer) revert NotBuyer();
        if (o.status != Status.Paid) revert WrongStatus(o.status, Status.Paid);
        if (block.timestamp <= o.createdAt + FULFILLMENT_DEADLINE) revert DeadlineNotReached();

        o.status = Status.Refunded;
        uint256 total = o.cost + o.profit;

        if (total > 0) {
            bool ok = IERC20(o.token).transfer(o.buyer, total);
            if (!ok) revert TransferFailed();
        }

        emit EmergencyRefund(id, o.buyer, total);
    }

    /* ─── Views ──────────────────────────────────────────────────────── */

    function getOrder(bytes32 id) external view returns (Order memory) {
        return orders[id];
    }

    function disputeWindowEnd(bytes32 id) external view returns (uint64) {
        Order storage o = orders[id];
        if (o.fulfilledAt == 0) return 0;
        return o.fulfilledAt + DISPUTE_WINDOW;
    }

    function canClaimRefund(bytes32 id) external view returns (bool) {
        Order storage o = orders[id];
        return o.status == Status.Fulfilled &&
               block.timestamp <= o.fulfilledAt + DISPUTE_WINDOW;
    }

    function canReleaseProfit(bytes32 id) external view returns (bool) {
        Order storage o = orders[id];
        return o.status == Status.Fulfilled &&
               block.timestamp > o.fulfilledAt + DISPUTE_WINDOW;
    }
}

contracts/MockERC20.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title MockERC20
 * @notice Minimal BEP-20/ERC-20 for local Hardhat testing only.
 *         Anyone can mint — never deploy to mainnet.
 */
contract MockERC20 {
    string  public name;
    string  public symbol;
    uint8   public decimals;
    uint256 public totalSupply;

    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    constructor(string memory _name, string memory _symbol, uint8 _decimals) {
        name     = _name;
        symbol   = _symbol;
        decimals = _decimals;
    }

    function mint(address to, uint256 amount) external {
        totalSupply        += amount;
        balanceOf[to]      += amount;
        emit Transfer(address(0), to, amount);
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        allowance[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function transfer(address to, uint256 amount) external returns (bool) {
        _transfer(msg.sender, to, amount);
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        uint256 allowed = allowance[from][msg.sender];
        if (allowed != type(uint256).max) {
            require(allowed >= amount, "MockERC20: insufficient allowance");
            allowance[from][msg.sender] = allowed - amount;
        }
        _transfer(from, to, amount);
        return true;
    }

    function _transfer(address from, address to, uint256 amount) internal {
        require(balanceOf[from] >= amount, "MockERC20: insufficient balance");
        balanceOf[from] -= amount;
        balanceOf[to]   += amount;
        emit Transfer(from, to, amount);
    }
}

